// ─────────────────────────────────────────────────────────────────────────────
// Step4C_LoadContacts.groovy
// Odoo  res_partner  DB loader
//
// Receives ONE JSON row per FlowFile. Every key in the row is already an
// Odoo column name (produced by Step3C_TransformContacts). No MappingResolver
// needed — there is nothing left to alias-resolve.
//
// The only values NOT in the row are runtime constants (company_id, country_id,
// admin uid) which are read directly from the distributed cache / env vars.
// ─────────────────────────────────────────────────────────────────────────────

import groovy.json.JsonSlurper
import org.apache.commons.io.IOUtils
import java.nio.charset.StandardCharsets

def ff = session.get()
if (!ff) return

def ser   = { v, o -> o.write(v.toString().getBytes('UTF-8')) } as org.apache.nifi.distributed.cache.client.Serializer
def deser = { b -> new String(b, 'UTF-8') }                     as org.apache.nifi.distributed.cache.client.Deserializer

def safeLong = { def v ->
    if (v == null) return null
    def s = v?.toString()?.trim()
    if (!s || s == 'null' || s == 'CLEARED') return null
    try { return s.toLong() } catch(ignored) { return null }
}

def nvl = { def v ->
    def s = v?.toString()?.trim()
    (s && s != 'null') ? s : null
}

try {
    // ── 1. Read JSON row ──────────────────────────────────────────────────────
    def jsonText = ''
    session.read(ff, { is ->
        jsonText = IOUtils.toString(is, StandardCharsets.UTF_8)
    } as org.apache.nifi.processor.io.InputStreamCallback)

    def row = new JsonSlurper().parseText(jsonText)
    log.info('LoadContacts row: ' + row.toString()?.take(300))

    // ── 2. Read row fields — keys are already Odoo column names ──────────────
    def name     = nvl(row['name'])
    def gstin    = nvl(row['vat'])
    def custRank = row['customer_rank']?.toString()?.toInteger() ?: 0
    def suppRank = row['supplier_rank']?.toString()?.toInteger() ?: 0
    def street   = nvl(row['street'])
    def street2  = nvl(row['street2'])
    def zip      = nvl(row['zip'])
    def email    = nvl(row['email'])
    def phone    = nvl(row['phone'])
    def autopost = nvl(row['autopost_bills']) ?: 'nothing'
    def panEntityId = safeLong(ff.attributes['pan_entity_id'])
     log.info("panEntityId=${panEntityId}")

    // city: if Step3C wrote a dedicated city column use it;
    // otherwise peel it off the end of street2 (last comma segment)
    def city = nvl(row['city'])
    if (!city && street2) {
        def lastComma = street2.lastIndexOf(',')
        if (lastComma > 0) {
            city    = street2.substring(lastComma + 1).trim() ?: null
            street2 = street2.substring(0, lastComma).trim()  ?: null
        }
    }

    // state name written by Step3C as 'state_id/name'
    def stateName = nvl(row['state_id/name'])

    log.info("name=${name} gstin=${gstin} custRank=${custRank} suppRank=${suppRank}")
    log.info("street=${street} street2=${street2} city=${city} zip=${zip}")

    if (!name) {
        log.warn('Empty name — skipping')
        session.transfer(ff, REL_SUCCESS)
        return
    }

    // ── 3. Runtime constants — cache / env only, NOT from the row ────────────
    def cacheGet = { String key ->
        try {
            def v = CTL.cacheClient.get(key, ser, deser)
            return (v && v != 'CLEARED') ? v.trim() : null
        } catch(ignored) { return null }
    }

    def compId   = safeLong(cacheGet('lookup.company_id'))
    def ctryId   = safeLong(cacheGet('lookup.country_id_in') ?: cacheGet('lookup.country_id'))
    def adminUid = (System.getenv('PG_ADMIN_UID') ?: '1').toLong()
    def module   = System.getenv('MIGRATION_MODULE') ?: '__migration__'

    // state FK lives in cache as lookup.state.{canonical name}
    def stateId = stateName ? safeLong(cacheGet('lookup.state.' + stateName)) : null
    if (stateName && !stateId) log.warn("State not in cache: ${stateName} — stateId=null")

    // ── 4. External ID ────────────────────────────────────────────────────────
    def extId = nvl(row['id']) ?: TallyCleaners.makePartnerExtId(name, gstin)
    log.info("extId=${extId}")

    // ── 5. Cache check — already loaded? ─────────────────────────────────────
    def cacheKey = 'xid.partner.' + extId
    def cachedId = cacheGet(cacheKey)
    if (cachedId) {
        log.info("Partner already cached: ${name} → ${cachedId}")
        ff = session.putAttribute(ff, 'res_id',      cachedId)
        ff = session.putAttribute(ff, 'partner_id',  cachedId)
        ff = session.putAttribute(ff, 'partner_xid', extId)
        session.transfer(ff, REL_SUCCESS)
        return
    }

    // ── 6. DB check — XID already registered? ────────────────────────────────
    def existingId = null
    SQL.myPool.eachRow(
        'SELECT res_id FROM ir_model_data WHERE module=? AND name=?',
        [module, extId]
    ) { r -> existingId = r.getLong('res_id') }

    long resId
    if (existingId) {
        resId = existingId
        log.info("Partner already in DB: ${name} → ${resId}")

    } else {
        // ── 7. INSERT res_partner ─────────────────────────────────────────────
        def ps = SQL.myPool.connection.prepareStatement(
            '''INSERT INTO res_partner
               (name, vat, customer_rank, supplier_rank,
                street, street2, zip, city, email, phone,
                state_id, country_id, company_id,
                is_company, active, type,
                autopost_bills, partner_share, lang, tz,
                message_bounce, color, employee,l10n_in_pan_entity_id,
                create_uid, write_uid,
                create_date, write_date)
               VALUES (?,?,?,?, ?,?,?,?,?,?, ?,?,?, ?,?,?, ?,?,?,?, ?,?,?, ?,?,?, NOW(),NOW())
               RETURNING id'''
        )

        def setStr  = { int i, def v -> v ? ps.setString(i, v.toString()) : ps.setNull(i, java.sql.Types.VARCHAR)  }
        def setLong = { int i, def v -> v ? ps.setLong(i,   v.toLong())   : ps.setNull(i, java.sql.Types.INTEGER) }

        int p = 1
        ps.setString(p++, name)
        setStr(p++,  gstin)
        ps.setInt(p++, custRank)
        ps.setInt(p++, suppRank)
        setStr(p++,  street)
        setStr(p++,  street2)
        setStr(p++,  zip)
        setStr(p++,  city)
        setStr(p++,  email)
        setStr(p++,  phone)
        setLong(p++, stateId)
        setLong(p++, ctryId)
        setLong(p++, compId)
        ps.setBoolean(p++, true)      // is_company
        ps.setBoolean(p++, true)      // active
        ps.setString(p++,  'contact')
        ps.setString(p++,  autopost)
        ps.setBoolean(p++, true)      // partner_share
        ps.setString(p++,  'en_US')
        ps.setString(p++,  'Asia/Kolkata')
        ps.setInt(p++, 0)             // message_bounce
        ps.setInt(p++, 0)             // color
        ps.setBoolean(p++, false)     // employee
		if (panEntityId) ps.setLong(p++, panEntityId)
		else             ps.setNull(p++, java.sql.Types.INTEGER)

        ps.setLong(p++, adminUid)     // create_uid
        ps.setLong(p++, adminUid)     // write_uid


        def rs = ps.executeQuery()
        rs.next()
        resId = rs.getLong(1)
        ps.close()

        // ── 8. Backfill self-referencing columns ──────────────────────────────
        SQL.myPool.execute(
            'UPDATE res_partner SET commercial_partner_id=?, complete_name=? WHERE id=?',
            [resId, name, resId]
        )

        // ── 9. Register XID in ir_model_data ─────────────────────────────────
        SQL.myPool.execute(
            '''INSERT INTO ir_model_data (module, name, model, res_id, noupdate, create_date, write_date)
               VALUES (?,?,?,?,false,NOW(),NOW()) ON CONFLICT (module,name) DO NOTHING''',
            [module, extId, 'res.partner', resId]
        )

        log.info("Partner INSERTED: ${name} → ${resId}")
    }

    // ── 10. Populate caches ───────────────────────────────────────────────────
    CTL.cacheClient.put(cacheKey,              resId.toString(), ser, ser)
    CTL.cacheClient.put('partner.' + name,     resId.toString(), ser, ser)
    if (gstin) CTL.cacheClient.put('partner.gstin.' + gstin, resId.toString(), ser, ser)

    ff = session.putAttribute(ff, 'res_id',      resId.toString())
    ff = session.putAttribute(ff, 'partner_id',  resId.toString())
    ff = session.putAttribute(ff, 'partner_xid', extId)
    session.transfer(ff, REL_SUCCESS)

} catch (Exception e) {
    log.error('LoadContacts failed: ' + e.message, e)
    ff = session.putAttribute(ff, 'error',       e.message)
    ff = session.putAttribute(ff, 'error.cause', e.getCause()?.getMessage() ?: 'none')
    session.transfer(ff, REL_FAILURE)
}

import groovy.json.JsonOutput
import groovy.json.JsonSlurper
import org.apache.commons.io.IOUtils
import java.nio.charset.StandardCharsets

def ff = session.get(); if (!ff) return

def safeLong = { def v ->
    if (v == null) return null
    def s = v.toString().trim()
    if (s == '' || s == 'null' || s == 'CLEARED') return null
    try { return s.toLong() } catch(e) { return null }
}

def safeBigDecimal = { def v ->
    if (v == null) return BigDecimal.ZERO
    def s = v.toString().trim().replaceAll('[^0-9.]', '')
    if (s == '' || s == '.') return BigDecimal.ZERO
    try { return s.toBigDecimal() } catch(e) { return BigDecimal.ZERO }
}

def ser   = { v, o -> o.write(v.toString().getBytes('UTF-8')) } as org.apache.nifi.distributed.cache.client.Serializer
def deser = { b -> new String(b, 'UTF-8') }                     as org.apache.nifi.distributed.cache.client.Deserializer

try {
    // ── 1. Read JSON row ──────────────────────────────────────────────────
    def jsonText = ''
    session.read(ff, { inputStream ->
        jsonText = IOUtils.toString(inputStream, StandardCharsets.UTF_8)
    } as org.apache.nifi.processor.io.InputStreamCallback)

    log.info('JSON content: ' + jsonText?.take(300))

    def row = new JsonSlurper().parseText(jsonText)
    log.info('Parsed row: ' + row.toString())

    // ── 2. Read all fields directly from JSON row ─────────────────────────
    // No MappingResolver needed — Step3D already resolved/transformed everything.
    def nvl = { def v ->
        def s = v?.toString()?.trim()
        (s && s != 'null') ? s : null
    }

    def name        = nvl(row['name'])
    def defCode     = nvl(row['default_code'])?.take(64)
    def ptype       = nvl(row['type'])       ?: 'consu'
    def listPrice   = safeBigDecimal(row['list_price'])
    def stdPriceRaw = safeBigDecimal(row['standard_price'])
    def uomName     = nvl(row['uom_id/name'])    ?: 'Units'
    def catName     = nvl(row['categ_id/name'])
    def hsn         = nvl(row['l10n_in_hsn_code'])
    def descSaleRaw = nvl(row['description_sale'])
    def barcode     = nvl(row['barcode'])
    if (barcode && !(barcode =~ /^\d{8,13}$/)) barcode = null

    if (!name) {
        log.warn('Empty name — skipping')
        session.transfer(ff, REL_SUCCESS)
        return
    }

    log.info("name=${name} ptype=${ptype} listPrice=${listPrice} uomName=${uomName} catName=${catName}")

    // ── 3. Runtime constants ──────────────────────────────────────────────
    def compId   = safeLong(CTL.cacheClient.get('lookup.company_id', ser, deser)) ?: 1L
    def adminUid = (System.getenv('PG_ADMIN_UID') ?: '1').toLong()
    def module   = System.getenv('MIGRATION_MODULE') ?: '__migration__'

    // ── 4. Resolve UoM ───────────────────────────────────────────────────
    Long uomId = null
    try { uomId = safeLong(CTL.cacheClient.get('lookup.uom.' + uomName, ser, deser)) } catch(e) {}
    if (!uomId) {
        try { uomId = safeLong(CTL.cacheClient.get('lookup.uom.Units', ser, deser)) } catch(e) {}
    }
    if (!uomId) {
        SQL.myPool.eachRow(
            "SELECT id FROM uom_uom WHERE name->>'en_US' = ? OR name::text = ? LIMIT 1",
            [uomName, uomName]
        ) { r -> uomId = r.getLong('id') }
    }
    if (!uomId) throw new Exception("UoM '${uomName}' not found in cache or DB — re-run bootstrap")
    log.info("uomName=${uomName} uomId=${uomId}")

    // ── 5. Resolve product category ───────────────────────────────────────
    // Pass 1: cache
    // Pass 2: direct DB name match
    // Pass 3: auto-create under 'All'
    // catId used via string concat in INSERT so no JDBC integer/varchar issue.
    Long catId = null

    if (catName) {
        // Pass 1 — cache
        try { catId = safeLong(CTL.cacheClient.get('category.' + catName, ser, deser)) } catch(e) {}

        // Pass 2 — direct DB name match
        if (!catId) {
            SQL.myPool.eachRow(
                "SELECT id FROM product_category WHERE name = ? LIMIT 1",
                [catName]
            ) { r -> catId = r.getLong('id') }
        }

        if (catId) {
            try { CTL.cacheClient.put('category.' + catName, catId.toString(), ser, ser) } catch(e) {}
            log.info("catName=${catName} catId=${catId}")
        } else {
            log.warn("categ '${catName}' not found — will auto-create")
        }
    }

    // Pass 3 — auto-create if still not resolved

    log.info("Final catId=${catId}")

    // ── 6. Build JSONB values ─────────────────────────────────────────────
    // name wrapped as JSONB {en_US: value} for Odoo 17+
    def nameSafe     = name.replace("'", "''").replace('\\', '\\\\')
    def nameJson     = '{"en_US": "' + nameSafe + '"}'
    def stdPriceJson = JsonOutput.toJson([(compId.toString()): stdPriceRaw])
    def descSaleJson = descSaleRaw
        ? '{"en_US": "' + descSaleRaw.replace("'", "''").replace('\\', '\\\\') + '"}'
        : null

    // ── 7. Build external IDs ─────────────────────────────────────────────
    def csvXid = nvl(row['id'])
    def tmplExtId, prodExtId
    if (csvXid) {
        tmplExtId = csvXid.startsWith('tmpl_') ? csvXid
                        : 'tmpl_' + csvXid.replaceAll(/[^a-zA-Z0-9_]/, '_')
        prodExtId = 'prod_' + tmplExtId.substring(5)
    } else {
        def extBase = (defCode ?: name.take(30)).replaceAll(/[^a-zA-Z0-9]/, '_').toUpperCase()
        tmplExtId   = 'tmpl_' + extBase.take(25).replaceAll(/_$/, '')
        prodExtId   = 'prod_' + tmplExtId.substring(5)
    }
    def module2 = module   // groovy closure capture
    log.info("tmplExtId=${tmplExtId} prodExtId=${prodExtId}")

    // ── 8. Cache check — idempotency fast-path ────────────────────────────
    def tmplCacheKey = 'xid.product_template.' + tmplExtId
    def cachedTmplId = null
    try { cachedTmplId = CTL.cacheClient.get(tmplCacheKey, ser, deser) } catch(e) {}

    if (cachedTmplId && cachedTmplId != 'CLEARED' && cachedTmplId != '') {
        log.info("Product already cached: ${name} → ${cachedTmplId}")
        ff = session.putAttribute(ff, 'res_id', cachedTmplId)
        ff = session.putAttribute(ff, 'tmpl_xid', tmplExtId)
        session.transfer(ff, REL_SUCCESS)
        return
    }

    // ── 9. DB idempotency check ───────────────────────────────────────────
    def existingTmplId = null
    SQL.myPool.eachRow(
        "SELECT res_id FROM ir_model_data WHERE module = '" + module + "' AND name = '" + tmplExtId + "'"
    ) { r -> existingTmplId = r.getLong('res_id') }

    if (existingTmplId) {
        try { CTL.cacheClient.put(tmplCacheKey, existingTmplId.toString(), ser, ser) } catch(e) {}
        log.info("Product already in DB: ${name} → ${existingTmplId}")
        ff = session.putAttribute(ff, 'res_id', existingTmplId.toString())
        ff = session.putAttribute(ff, 'tmpl_xid', tmplExtId)
        session.transfer(ff, REL_SUCCESS)
        return
    }

    // ── 10. INSERT product_template ───────────────────────────────────────
    // String-concatenation SQL — catId as Long.toString() avoids integer/varchar error.
    def tmplId = null

SQL.myPool.eachRow(
    'INSERT INTO product_template ' +
    '(name, type, service_tracking, uom_id, ' +
    'categ_id, company_id, list_price, default_code, ' +
    'sale_ok, purchase_ok, active, ' +
    'invoice_policy, ' +
    'has_configurable_attributes, color, sequence, ' +
    'create_uid, write_uid, create_date, write_date) ' +
    'VALUES (' +
    '\'' + nameJson + '\'::jsonb, ' +
    '\'' + ptype + '\', ' +
    '\'no\', ' +
    uomId + ', ' +
    (catId  ? catId.toString()  : 'NULL') + ', ' +
    (compId ? compId.toString() : 'NULL') + ', ' +
    listPrice + ', ' +
    (defCode ? '\'' + defCode.replace("'", "''") + '\'' : 'NULL') + ', ' +
    'true, true, true, ' +
    '\'order\', ' +
    'false, 0, 1, ' +
    compId + ', ' + compId + ', ' +
    'NOW(), NOW()) RETURNING id'
) { r -> tmplId = r.getLong('id') }

    log.info("product_template INSERTED: ${name} → ${tmplId}")

    SQL.myPool.execute(
        'INSERT INTO ir_model_data (module, name, model, res_id, noupdate, create_date, write_date) ' +
        'VALUES (\'' + module + '\', \'' + tmplExtId + '\', \'product.template\', ' +
        tmplId + ', false, NOW(), NOW()) ON CONFLICT (module, name) DO NOTHING'
    )

    // ── 11. INSERT product_product (1 default variant) ────────────────────
    def existingProdId = null
    SQL.myPool.eachRow(
        "SELECT res_id FROM ir_model_data WHERE module = '" + module + "' AND name = '" + prodExtId + "'"
    ) { r -> existingProdId = r.getLong('res_id') }

    def prodId = null
    if (!existingProdId) {
        SQL.myPool.eachRow(
            'INSERT INTO product_product ' +
            '(product_tmpl_id, active, default_code, barcode, ' +
            'standard_price, combination_indices, ' +
            'create_uid, write_uid, create_date, write_date) ' +
            'VALUES (' +
            tmplId + ', true, ' +
            (defCode ? '\'' + defCode.replace("'", "''") + '\'' : 'NULL') + ', ' +
            (barcode ? '\'' + barcode.replace("'", "''") + '\'' : 'NULL') + ', ' +
            '\'' + stdPriceJson + '\'::jsonb, \'\', ' +
            compId + ', ' + compId + ', ' +
            'NOW(), NOW()) RETURNING id'
        ) { r -> prodId = r.getLong('id') }

        SQL.myPool.execute(
            'INSERT INTO ir_model_data (module, name, model, res_id, noupdate, create_date, write_date) ' +
            'VALUES (\'' + module + '\', \'' + prodExtId + '\', \'product.product\', ' +
            prodId + ', false, NOW(), NOW()) ON CONFLICT (module, name) DO NOTHING'
        )
        log.info("product_product INSERTED: ${prodId} (tmpl: ${tmplId})")
    }

    // ── 12. Cache + attributes ────────────────────────────────────────────
    try { CTL.cacheClient.put(tmplCacheKey, tmplId.toString(), ser, ser) } catch(e) {}
    try { CTL.cacheClient.put('product.' + name, tmplId.toString(), ser, ser) } catch(e) {}

    ff = session.putAttribute(ff, 'res_id',   tmplId.toString())
    ff = session.putAttribute(ff, 'prod_id',  prodId?.toString() ?: '')
    ff = session.putAttribute(ff, 'tmpl_xid', tmplExtId)
    session.transfer(ff, REL_SUCCESS)

} catch(e) {
    log.error('Product insert failed: ' + e.message, e)
    ff = session.putAttribute(ff, 'error',       e.message)
    ff = session.putAttribute(ff, 'error.cause', e.getCause()?.getMessage() ?: 'none')
    session.transfer(ff, REL_FAILURE)
}

// ─────────────────────────────────────────────────────────────────────────────
// Step3D_TransformProducts.groovy  —  NiFi ExecuteScript (Groovy)
// ─────────────────────────────────────────────────────────────────────────────

import TallyCleaners_Product
import org.apache.nifi.processor.io.StreamCallback
import org.apache.nifi.processor.io.InputStreamCallback
import groovy.json.JsonSlurper
import java.nio.charset.StandardCharsets

// ═════════════════════════════════════════════════════════════════════════════
// MAIN
// ═════════════════════════════════════════════════════════════════════════════

def flowFile = session.get()
if (!flowFile) return

try {
    // ── 1. Load mappings ──────────────────────────────────────────────────────
    def mappingsPath = flowFile.getAttribute('mappings.path') ?: '/home/ubuntu/Raw_tally_data/mappings.json'
    log.info("[Step3D] STEP1: Loading mappings from: ${mappingsPath}")

    def mappingJson = new File(mappingsPath).text
    def mappings    = new JsonSlurper().parseText(mappingJson)

    // UOM map — normalise keys to lower-case for lookup
    def uomMapRaw = mappings.uom_map ?: [:]
    def uomMap    = uomMapRaw.collectEntries { k, v -> [k.toString().toLowerCase(), v.toString()] }

    // Skip-row sentinel values — driven entirely by mappings.json, no hardcoding here
    def skipRowValues = (mappings.skip_row_values ?: [])
        .collect { it.toString().trim().toLowerCase() } as Set

    // Pull field configs — these drive ALL column resolution
    def ptFields = mappings.tables?.product_template?.fields ?: [:]
    def ppFields = mappings.tables?.product_product?.fields  ?: [:]

    log.info("[Step3D] STEP1: product_template fields: ${ptFields.size()}, " +
             "product_product fields: ${ppFields.size()}, " +
             "skip_row_values: ${skipRowValues}")

    if (ptFields.isEmpty()) {
        log.error('[Step3D] product_template fields missing from mappings.json — ' +
                  'check mappings.path attribute and JSON structure')
        session.transfer(flowFile, REL_FAILURE)
        return
    }

    // ── 2. Read CSV ───────────────────────────────────────────────────────────
    String csvText = ''
    session.read(flowFile, { inputStream ->
        csvText = new String(inputStream.bytes, StandardCharsets.UTF_8)
                   .replaceFirst(/^\uFEFF/, '')
    } as InputStreamCallback)

    def lines = csvText.readLines().findAll { it.trim() }
    log.info("[Step3D] STEP2: Total lines: ${lines.size()}")

    if (lines.size() < 2) {
        log.warn('[Step3D] Empty or header-only products CSV — skipping')
        session.transfer(flowFile, REL_FAILURE)
        return
    }

    // ── 3. Auto-detect header row (skip junk/title rows at top) ──────────────
    // Build a full alias set from mappings — any cell that matches an alias
    // is evidence this is the header row.
    def allAliases = [] as Set
    [ptFields, ppFields].each { fieldMap ->
        fieldMap.each { odooField, fm ->
            if (fm.source_col)
                allAliases << fm.source_col.toString().trim().toLowerCase()
            if (fm.source_cols instanceof List)
                fm.source_cols.each { allAliases << it.toString().trim().toLowerCase() }
        }
    }

    int headerLineIdx = -1
    for (int i = 0; i < Math.min(lines.size(), 10); i++) {
        def cols  = TallyCleaners_Product.splitCsvLine(lines[i])
        def lower = cols*.trim()*.toLowerCase()
        int matchCount = lower.count { cell -> cell && allAliases.contains(cell) }
        if (matchCount >= 2) { headerLineIdx = i; break }
        def nameAliases = [] as Set
		def nameFm = ptFields['name']
		if (nameFm?.source_col)  nameAliases << nameFm.source_col.toString().trim().toLowerCase()
		if (nameFm?.source_cols instanceof List)
    	nameFm.source_cols.each { nameAliases << it.toString().trim().toLowerCase() }

		if (matchCount >= 1 && lower.any { cell -> nameAliases.contains(cell) }) {
    		headerLineIdx = i; break
		}
    }

    if (headerLineIdx < 0) {
        log.error('[Step3D] Cannot find header row in first 10 lines. First line: ' + lines[0])
        session.transfer(flowFile, REL_FAILURE)
        return
    }

    if (headerLineIdx > 0)
        log.info("[Step3D] Skipped ${headerLineIdx} junk row(s). Header: ${lines[headerLineIdx]}")

    def headers = TallyCleaners_Product.splitCsvLine(lines[headerLineIdx])

    // ── 4. Build header → index map (lower-cased, non-empty keys only) ────────
    def headerIdx = [:]
    headers.eachWithIndex { h, i ->
        def key = h?.trim()?.toLowerCase() ?: ''
        if (key) headerIdx[key] = i
    }

    log.info("[Step3D] STEP4: headerIdx (non-empty only): ${headerIdx}")

    // ── 5. Alias-driven column resolver ───────────────────────────────────────
    def resolveColIdx = { String odooField, Map fieldMap ->
        def fm = fieldMap[odooField]
        if (!fm) {
            log.warn("[Step3D] STEP5: '${odooField}' not in fieldMap")
            return -1
        }

        def candidates = []
        if (fm.source_col)                              candidates << fm.source_col.toString().trim()
        if (fm.source_cols instanceof List) candidates += fm.source_cols*.toString()*.trim()
        candidates = candidates.findAll { it }

        // Pass 1 — exact match
        for (String alias in candidates) {
            def aliasL = alias.toLowerCase()
            if (!aliasL) continue
            if (headerIdx.containsKey(aliasL)) {
                log.info("[Step3D] '${odooField}' → EXACT '${alias}' → col ${headerIdx[aliasL]}")
                return headerIdx[aliasL]
            }
        }

        // Pass 2 — contains fallback
        for (String alias in candidates) {
            def aliasL = alias.toLowerCase()
            if (!aliasL) continue
            def found = headerIdx.find { k, v ->
                k && k.trim() && (k.contains(aliasL) || aliasL.contains(k))
            }
            if (found) {
                log.info("[Step3D] '${odooField}' → CONTAINS '${alias}' ~ '${found.key}' → col ${found.value}")
                return found.value
            }
        }

        log.warn("[Step3D] '${odooField}' → NO MATCH in headers")
        return -1
    }

    // ── 6. Resolve all column indices from mappings ───────────────────────────
    //   product_template fields
    int nameIdx     = resolveColIdx('name',             ptFields)
    int priceIdx    = resolveColIdx('list_price',       ptFields)
    int typeIdx     = resolveColIdx('type',             ptFields)
    int defCodeIdx  = resolveColIdx('default_code',     ptFields)
    int categIdx    = resolveColIdx('categ_id',         ptFields)
    int hsnIdx      = resolveColIdx('l10n_in_hsn_code', ptFields)
    int descIdx     = resolveColIdx('description_sale', ptFields)
    int uomIdx      = resolveColIdx('uom_id',           ptFields)
    int uomPoIdx    = resolveColIdx('uom_po_id',        ptFields)
    int storableIdx = resolveColIdx('is_storable',      ptFields)
    //   product_product fields
    int costIdx     = resolveColIdx('standard_price',   ppFields)
    int barcodeIdx  = resolveColIdx('barcode',          ppFields)

    log.info("[Step3D] STEP6: FINAL column indices — " +
             "name:${nameIdx} price:${priceIdx} type:${typeIdx} defCode:${defCodeIdx} " +
             "categ:${categIdx} hsn:${hsnIdx} desc:${descIdx} uom:${uomIdx} " +
             "uomPo:${uomPoIdx} storable:${storableIdx} cost:${costIdx} barcode:${barcodeIdx}")

    if (nameIdx < 0) {
        log.error('[Step3D] Cannot find product name column — check source_col/source_cols ' +
                  'for "name" field under product_template in mappings.json')
        session.transfer(flowFile, REL_FAILURE)
        return
    }

    // ── 7. Output columns ─────────────────────────────────────────────────────
    def OUT_COLS = [
        'id',               // XID  — tmpl_<SLUG25>
        'name',
        'default_code',
        'type',             // "consu" or "service"
        'is_storable',      // "true" / "false"
        'list_price',
        'standard_price',
        'uom_id/name',
        'uom_po_id/name',
        'categ_id/name',
        'l10n_in_hsn_code',
        'description_sale',
        'barcode',
    ]

    def sb        = new StringBuilder()
    def seenXids  = [:] as LinkedHashMap
    def seenCodes = [:] as LinkedHashMap
    int written   = 0
    int skipped   = 0

    sb.append(OUT_COLS.join(',')).append('\n')

    // ── 8. Process rows ───────────────────────────────────────────────────────
    for (int i = headerLineIdx + 1; i < lines.size(); i++) {
        def cells = TallyCleaners_Product.splitCsvLine(lines[i])

        // ── a) name — mandatory ───────────────────────────────────────────────
        def rawName = TallyCleaners_Product.cell(cells, nameIdx)
        if (!rawName) { skipped++; continue }

        def name = TallyCleaners_Product.cleanName(rawName)

        // ── b) skip Tally summary / header rows (driven by mappings.json) ─────
        if (TallyCleaners_Product.isSkipRow(name, skipRowValues)) {
            skipped++; continue
        }

        // ── c) sanity: enough columns? ────────────────────────────────────────
        def maxNeeded = [nameIdx, hsnIdx, priceIdx, costIdx, typeIdx]
                            .findAll { it >= 0 }.max() + 1
        if (cells.size() < maxNeeded) {
            log.warn("[Step3D] Row ${i} has only ${cells.size()} cols (need ${maxNeeded}) " +
                     "name=[${name}] — skipping")
            skipped++; continue
        }

        // ── d) id (XID) ───────────────────────────────────────────────────────
        def xidSlug = TallyCleaners_Product.toSlugUnderscore(name)
        def xidBase = 'tmpl_' + xidSlug
        def xidCnt  = (seenXids[xidBase] ?: 0) + 1
        seenXids[xidBase] = xidCnt
        def xid = xidCnt > 1 ? xidBase.take(22) + '_' + xidCnt : xidBase

        // ── e) default_code ───────────────────────────────────────────────────
        def rawCode  = TallyCleaners_Product.cell(cells, defCodeIdx)
        def codeBase = rawCode ? rawCode.take(20) : TallyCleaners_Product.toSlugHyphen(name)
        def codeCnt  = (seenCodes[codeBase] ?: 0) + 1
        seenCodes[codeBase] = codeCnt
        def code = codeCnt > 1
            ? codeBase.take(20 - ("-${codeCnt}".length())) + "-${codeCnt}"
            : codeBase

        // ── f) barcode ────────────────────────────────────────────────────────
        def rawBarcode = TallyCleaners_Product.cell(cells, barcodeIdx)
        def barcode    = (rawBarcode && rawBarcode =~ /^\d{8,13}$/) ? rawBarcode : ''

        // ── g) product type + is_storable ─────────────────────────────────────
        def ptype      = TallyCleaners_Product.normalizeProductType(
                             TallyCleaners_Product.cell(cells, typeIdx),
                             TallyCleaners_Product.cell(cells, storableIdx))
        def isStorable = (ptype == 'consu') ? 'true' : 'false'

        // ── h) prices ─────────────────────────────────────────────────────────
        def listPrice     = TallyCleaners_Product.parseNumber(TallyCleaners_Product.cell(cells, priceIdx))
        def standardPrice = TallyCleaners_Product.parseNumber(TallyCleaners_Product.cell(cells, costIdx))

        // ── i) UOM ────────────────────────────────────────────────────────────
        def uom    = TallyCleaners_Product.normalizeUom(uomMap, TallyCleaners_Product.cell(cells, uomIdx))
        def rawPo  = TallyCleaners_Product.cell(cells, uomPoIdx)
        def uomPo  = rawPo ? TallyCleaners_Product.normalizeUom(uomMap, rawPo) : uom

        // ── j) category — from CSV column; dynamic derivation as fallback ─────
        def rawCateg = TallyCleaners_Product.cell(cells, categIdx)
        def categ    = rawCateg ?: TallyCleaners_Product.deriveCategory(name)

        // ── k) HSN ────────────────────────────────────────────────────────────
        def hsn = TallyCleaners_Product.parseCode(TallyCleaners_Product.cell(cells, hsnIdx))

        // ── l) description_sale ───────────────────────────────────────────────
        def descSale = TallyCleaners_Product.cell(cells, descIdx)

        // ── m) assemble row ───────────────────────────────────────────────────
        def row = [
            xid, name, code, ptype, isStorable,
            listPrice, standardPrice,
            uom, uomPo,
            categ, hsn, descSale, barcode
        ]
        sb.append(row.collect { TallyCleaners_Product.escapeCsv(it as String) }.join(','))
          .append('\n')
        written++
    }

    if (written == 0) {
        log.warn('[Step3D] No valid product rows produced — check source file')
        session.transfer(flowFile, REL_FAILURE)
        return
    }

    // ── 9. Write output ───────────────────────────────────────────────────────
    def outBytes = sb.toString().getBytes(StandardCharsets.UTF_8)
    flowFile = session.write(flowFile, { rawIn, rawOut ->
        rawOut.write(outBytes)
    } as StreamCallback)

    flowFile = session.putAllAttributes(flowFile, [
        'mime.type'    : 'text/csv',
        'filename'     : '04_products.csv',
        'staging.file' : '04_products.csv',
        'entity.type'  : 'products',
        'row.count'    : written.toString(),
        'skip.count'   : skipped.toString(),
    ])

    log.info("[Step3D] 04_products.csv written — ${written} rows, ${skipped} skipped")
    session.transfer(flowFile, REL_SUCCESS)

} catch (Exception e) {
    log.error("[Step3D] Transform failed: ${e.message}", e)
    session.transfer(flowFile, REL_FAILURE)
}

import groovy.json.JsonOutput

// ── Serializer / Deserializer ─────────────────────────────────────────────
def ser   = { v, o -> o.write(v.bytes) } as org.apache.nifi.distributed.cache.client.Serializer
def deser = { b -> new String(b) }       as org.apache.nifi.distributed.cache.client.Deserializer

// ── Cache client via CTL. prefix ──────────────────────────────────────────
def cache = CTL.cacheClient

try {

    // ── company_id ────────────────────────────────────────────────────────
    def compId
    SQL.myPool.eachRow("SELECT id FROM res_company WHERE id = 1") { row ->
        compId = row.getLong(1)
    }
    cache.put('lookup.company_id', compId.toString(), ser, ser)
    cache.put('lookup.admin_uid', '1', ser, ser) //default
    log.info("Cached company_id: ${compId}")

    // ── currency_id (INR) ─────────────────────────────────────────────────
    def currencyId
    SQL.myPool.eachRow("SELECT id FROM res_currency WHERE name = 'INR'") { row ->
        currencyId = row.getLong(1)
    }
    cache.put('lookup.currency_id', currencyId.toString(), ser, ser)
    cache.put('lookup.currency_id_inr', currencyId.toString(), ser, ser)
    log.info("Cached currency_id: ${currencyId}")

    // ── country_id (India) ────────────────────────────────────────────────
    def ctryId
    SQL.myPool.eachRow("SELECT id FROM res_country WHERE code = 'IN'") { row ->
        ctryId = row.getLong(1)
    }
    cache.put('lookup.country_id', ctryId.toString(), ser, ser)
    cache.put('lookup.country_id_in', ctryId.toString(), ser, ser)
    log.info("Cached country_id: ${ctryId}")

    // ── Detect name column type helper ────────────────────────────────────
    def getNameColType = { tableName ->
        def colType = ''
        SQL.myPool.eachRow("""
            SELECT data_type FROM information_schema.columns
            WHERE table_name = '${tableName}' AND column_name = 'name'
        """) { row -> colType = row.getString(1) }
        return colType
    }

    // ── states ────────────────────────────────────────────────────────────
    def states = [:]
    def stateQuery = getNameColType('res_country_state') == 'jsonb'
        ? "SELECT name->>'en_US' AS state_name, id FROM res_country_state WHERE country_id = ${ctryId}"
        : "SELECT name AS state_name, id FROM res_country_state WHERE country_id = ${ctryId}"

    SQL.myPool.eachRow(stateQuery) { row ->
        def stateName = row.getString('state_name')
        if (stateName) {
            states[stateName] = row.getLong('id')
            cache.put("lookup.state.${stateName}", row.getLong('id').toString(), ser, ser)
        }
    }
    log.info("Cached all states: ${states.size()} entries")

    // ── uoms ──────────────────────────────────────────────────────────────
    def uoms = [:]
    def uomQuery = getNameColType('uom_uom') == 'jsonb'
        ? "SELECT name->>'en_US' AS uom_name, id FROM uom_uom WHERE active = true"
        : "SELECT name AS uom_name, id FROM uom_uom WHERE active = true"

    SQL.myPool.eachRow(uomQuery) { row ->
        def uomName = row.getString('uom_name')
        if (uomName) {
            uoms[uomName] = row.getLong('id')
            cache.put("lookup.uom.${uomName}", row.getLong('id').toString(), ser, ser)
        }
    }
    log.info("Cached all UOMs: ${uoms.size()} entries")

    // ── journals ──────────────────────────────────────────────────────────
    def journals = [:]
    def journalQuery = getNameColType('account_journal') == 'jsonb'
        ? "SELECT name->>'en_US' AS journal_name, id FROM account_journal WHERE company_id = ${compId}"
        : "SELECT name AS journal_name, id FROM account_journal WHERE company_id = ${compId}"

    SQL.myPool.eachRow(journalQuery) { row ->
        def journalName = row.getString('journal_name')
        if (journalName) {
            journals[journalName] = row.getLong('id')
            cache.put("lookup.journal.${journalName}", row.getLong('id').toString(), ser, ser)
        }
    }
    log.info("Cached all journals: ${journals.size()} entries")

    // ── Build JSON payload ────────────────────────────────────────────────
    def payload = [
        company_id  : compId,
        currency_id : currencyId,
        country_id  : ctryId,
        states      : states,
        uoms        : uoms,
        journals    : journals
    ]

    def jsonOutput = JsonOutput.prettyPrint(JsonOutput.toJson(payload))
    log.info("Bootstrap complete: all lookup IDs cached successfully")

    // ── Write JSON into FlowFile and transfer to SUCCESS ──────────────────
    def ff = session.get() ?: session.create()
    ff = session.write(ff, { outputStream ->
        outputStream.write(jsonOutput.getBytes('UTF-8'))
    } as org.apache.nifi.processor.io.OutputStreamCallback)

    session.putAttribute(ff, 'mime.type', 'application/json')
    session.transfer(ff, REL_SUCCESS)

} catch (Exception e) {
    log.error("Bootstrap error: ${e.message}", e)
    def ff = session.get() ?: session.create()
    session.transfer(ff, REL_FAILURE)
}

import groovy.json.JsonSlurper
import org.apache.commons.io.IOUtils
import java.nio.charset.StandardCharsets

def ff = session.get()
if (!ff) return

def ser   = { v, o -> o.write(v.toString().getBytes('UTF-8')) } as org.apache.nifi.distributed.cache.client.Serializer
def deser = { b -> new String(b, 'UTF-8') }                     as org.apache.nifi.distributed.cache.client.Deserializer

def safeLong = { def v ->
    if (v == null) return null
    def s = v?.toString()?.trim()
    if (!s || s == 'null' || s == 'CLEARED') return null
    try { return s.toLong() } catch (ignored) { return null }
}

def nvl = { def v ->
    def s = v?.toString()?.trim()
    (s && s != 'null') ? s : null
}

try {
    // ── 1. Read JSON row ──────────────────────────────────────────────────────
    def jsonText = ''
    session.read(ff, { is ->
        jsonText = IOUtils.toString(is, StandardCharsets.UTF_8)
    } as org.apache.nifi.processor.io.InputStreamCallback)

    def row = new JsonSlurper().parseText(jsonText)
    log.info('LoadTaxGroup row: ' + row.toString()?.take(300))

    // ── 2. Read row fields ────────────────────────────────────────────────────
    def taxName  = nvl(row['name'])
    def groupName = nvl(row['tax_group_name'])

    if (!taxName || taxName == 'name') {
        log.warn('Header or empty row — skipping')
        session.transfer(ff, REL_SUCCESS)
        return
    }
    if (!groupName) {
        log.warn("No tax_group_name for tax '${taxName}' — skipping")
        session.transfer(ff, REL_SUCCESS)
        return
    }

    log.info("taxName=${taxName} groupName=${groupName}")

    // ── 3. Runtime constants — cache / env only ───────────────────────────────
    def cacheGet = { String key ->
        try {
            def v = CTL.cacheClient.get(key, ser, deser)
            return (v && v != 'CLEARED') ? v.trim() : null
        } catch (ignored) { return null }
    }

    def compId   = safeLong(cacheGet('lookup.company_id')) ?: 1L
    def ctryId   = safeLong(cacheGet('lookup.country_id_in') ?: cacheGet('lookup.country_id'))
    def adminUid = (System.getenv('PG_ADMIN_UID') ?: '1').toLong()
    def module   = System.getenv('MIGRATION_MODULE') ?: '__migration__'

    if (!ctryId) throw new Exception('country_id not in cache — re-run Bootstrap')

    // ── 4. Build ext_id from group name ──────────────────────────────────────
    def groupSlug = groupName.toLowerCase().replaceAll(/[^a-z0-9]/, '_')
    def extId     = 'tally_tax_group_' + groupSlug

    // ── 5. Cache check ────────────────────────────────────────────────────────
    def cacheKey   = 'taxgroup.' + groupSlug
    def cachedId   = cacheGet(cacheKey)
    if (cachedId) {
        log.info("Tax group already cached: ${groupName} → ${cachedId}")
        ff = session.putAttribute(ff, 'tax_group_id',   cachedId)
        ff = session.putAttribute(ff, 'tax_group_name', groupName)
        ff = session.putAttribute(ff, 'tax_name',       taxName)
        session.transfer(ff, REL_SUCCESS)
        return
    }

    // ── 6. DB check ───────────────────────────────────────────────────────────
    def existingId = null
    SQL.myPool.eachRow(
        'SELECT res_id FROM ir_model_data WHERE module=? AND name=?',
        [module, extId]
    ) { r -> existingId = r.getLong('res_id') }

    long resId
    if (existingId) {
        resId = existingId
        log.info("Tax group already in DB: ${groupName} → ${resId}")

    } else {
        // ── 7. Build JSONB name ───────────────────────────────────────────────
        def nameSafe = groupName.replace('"', '\\"')
        def nameJson = "{\"en_US\": \"${nameSafe}\"}"

        // ── 8. INSERT account_tax_group ───────────────────────────────────────
        def ps = SQL.myPool.connection.prepareStatement(
            '''INSERT INTO account_tax_group
               (name, sequence, company_id, country_id,
                create_uid, write_uid, create_date, write_date)
               VALUES (?::jsonb, 10, ?, ?, ?, ?, NOW(), NOW())
               RETURNING id'''
        )
        ps.setString(1, nameJson)
        ps.setLong(2,   compId)
        ps.setLong(3,   ctryId)
        ps.setLong(4,   adminUid)
        ps.setLong(5,   adminUid)

        def rs = ps.executeQuery()
        rs.next()
        resId = rs.getLong(1)
        ps.close()

        // ── 9. Register XID ───────────────────────────────────────────────────
        SQL.myPool.execute(
            '''INSERT INTO ir_model_data (module, name, model, res_id, noupdate, create_date, write_date)
               VALUES (?,?,?,?,false,NOW(),NOW()) ON CONFLICT (module,name) DO NOTHING''',
            [module, extId, 'account.tax.group', resId]
        )

        log.info("Tax group INSERTED: ${groupName} → ${resId}")
    }

    // ── 10. Cache for LoadTax script ──────────────────────────────────────────
    CTL.cacheClient.put(cacheKey, resId.toString(), ser, ser)

    ff = session.putAttribute(ff, 'tax_group_id',   resId.toString())
    ff = session.putAttribute(ff, 'tax_group_name', groupName)
    ff = session.putAttribute(ff, 'tax_name',       taxName)
    session.transfer(ff, REL_SUCCESS)

} catch (Exception e) {
    log.error('LoadTaxGroup failed: ' + e.message, e)
    ff = session.putAttribute(ff, 'error',       e.message)
    ff = session.putAttribute(ff, 'error.cause', e.getCause()?.getMessage() ?: 'none')
    session.transfer(ff, REL_FAILURE)
}

// ─────────────────────────────────────────────────────────────────────────────
// Step3A_TransformTaxes.groovy
// ─────────────────────────────────────────────────────────────────────────────

import TallyCleaners_Taxes
import org.apache.nifi.processor.io.StreamCallback
import org.apache.nifi.processor.io.InputStreamCallback
import groovy.json.JsonSlurper
import java.nio.charset.StandardCharsets

// ══════════════════════════════════════════════════════════════════════════════
// MAIN
// ══════════════════════════════════════════════════════════════════════════════

def flowFile = session.get()
if (!flowFile) return

try {
    // ── 1. Load mappings ──────────────────────────────────────────────────────
    def mappingsPath = flowFile.getAttribute('mappings.path') ?: '/home/ubuntu/Raw_tally_data/mappings.json'
    log.info("[Step3A] STEP1: Loading mappings from: ${mappingsPath}")

    def mappings   = new JsonSlurper().parseText(new File(mappingsPath).text)
    def taxFields  = mappings.tables?.account_tax?.fields  ?: [:]
    def moveFields = mappings.tables?.account_move?.fields ?: [:]

    if (taxFields.isEmpty()) {
        log.error('[Step3A] account_tax fields missing from mappings.json')
        session.transfer(flowFile, REL_FAILURE); return
    }

    def taxKeywords      = (mappings.line_type_patterns?.tax_keywords      ?: []).collect { it.toString().toLowerCase() }
    def roundingKeywords = (mappings.line_type_patterns?.rounding_keywords ?: []).collect { it.toString().toLowerCase() }
    def taxGroupPatterns = (mappings.tax_group_patterns ?: [:])
                              .collectEntries { k, v -> [k.toString().toLowerCase(), v.toString()] }
    def purchaseTypeKw   = (mappings.voucher_classifier?.purchase_types    ?: []).collect { it.toString().toLowerCase() }
    def purchaseTaxGrpK  = taxGroupPatterns
                              .findAll { k, v -> v.toLowerCase() in ['tds', 'tcs'] }
                              .keySet() as Set

    if (taxKeywords.isEmpty())
        log.warn('[Step3A] line_type_patterns.tax_keywords is empty — no tax rows will be detected')

    log.info("[Step3A] STEP1: taxFields=${taxFields.size()} taxKeywords=${taxKeywords} " +
             "roundingKeywords=${roundingKeywords} taxGroupPatterns=${taxGroupPatterns} " +
             "purchaseTypeKw=${purchaseTypeKw} purchaseTaxGrpK=${purchaseTaxGrpK}")

    // ── 2. Read CSV ───────────────────────────────────────────────────────────
    String csvText = ''
    session.read(flowFile, { inputStream ->
        csvText = new String(inputStream.bytes, StandardCharsets.UTF_8)
                   .replaceFirst(/^\uFEFF/, '')
    } as InputStreamCallback)

    def lines = csvText.readLines().findAll { it.trim() }
    log.info("[Step3A] STEP2: Total lines: ${lines.size()}")

    if (lines.size() < 2) {
        log.warn('[Step3A] Empty or header-only CSV — skipping')
        session.transfer(flowFile, REL_FAILURE); return
    }

    // ── 3. Auto-detect header row ─────────────────────────────────────────────
    def allAliases = [] as Set
    [taxFields, moveFields].each { fieldMap ->
        fieldMap.each { odooField, fm ->
            if (fm.source_col)
                allAliases << fm.source_col.toString().trim().toLowerCase()
            if (fm.source_cols instanceof List)
                fm.source_cols.each { allAliases << it.toString().trim().toLowerCase() }
        }
    }

    def nameFm      = taxFields['name']
    def nameAliases = [] as Set
    if (nameFm?.source_col) nameAliases << nameFm.source_col.toString().trim().toLowerCase()
    if (nameFm?.source_cols instanceof List)
        nameFm.source_cols.each { nameAliases << it.toString().trim().toLowerCase() }

    int headerLineIdx = -1
    for (int i = 0; i < Math.min(lines.size(), 10); i++) {
        def cols  = TallyCleaners_Taxes.splitCsvLine(lines[i])
        def lower = cols*.trim()*.toLowerCase()
        int matchCount = lower.count { c -> c && allAliases.contains(c) }
        if (matchCount >= 2) { headerLineIdx = i; break }
        if (matchCount >= 1 && lower.any { c -> nameAliases.contains(c) }) { headerLineIdx = i; break }
    }

    if (headerLineIdx < 0) {
        log.error('[Step3A] Cannot find header row in first 10 lines. First line: ' + lines[0])
        session.transfer(flowFile, REL_FAILURE); return
    }

    if (headerLineIdx > 0)
        log.info("[Step3A] Skipped ${headerLineIdx} junk row(s). Header: ${lines[headerLineIdx]}")

    def headers = TallyCleaners_Taxes.splitCsvLine(lines[headerLineIdx])

    // ── 4. Build header → index map ───────────────────────────────────────────
    def headerIdx = [:]
    headers.eachWithIndex { h, i ->
        def key = h?.trim()?.toLowerCase() ?: ''
        if (key) headerIdx[key] = i
    }
    log.info("[Step3A] STEP4: headerIdx: ${headerIdx}")

    // ── 5. Alias-driven column resolver ───────────────────────────────────────
    def resolveColIdx = { String odooField, Map fields ->
        def fm = fields[odooField]
        if (!fm) { log.warn("[Step3A] '${odooField}' not in fields"); return -1 }

        def candidates = []
        if (fm.source_col)                              candidates << fm.source_col.toString().trim()
        if (fm.source_cols instanceof List) candidates += fm.source_cols*.toString()*.trim()
        candidates = candidates.findAll { it }

        // Pass 1 — exact match
        for (String alias in candidates) {
            def aliasL = alias.toLowerCase()
            if (!aliasL) continue
            if (headerIdx.containsKey(aliasL)) {
                log.info("[Step3A] '${odooField}' → EXACT '${alias}' → col ${headerIdx[aliasL]}")
                return headerIdx[aliasL]
            }
        }
        // Pass 2 — contains fallback
        for (String alias in candidates) {
            def aliasL = alias.toLowerCase()
            if (!aliasL) continue
            def found = headerIdx.find { k, v -> k && k.trim() && (k.contains(aliasL) || aliasL.contains(k)) }
            if (found) {
                log.info("[Step3A] '${odooField}' → CONTAINS '${alias}' ~ '${found.key}' → col ${found.value}")
                return found.value
            }
        }
        log.warn("[Step3A] '${odooField}' → NO MATCH in headers")
        return -1
    }

    // ── 6. Resolve column indices from mappings ───────────────────────────────
    // account_tax fields
    int partIdx    = resolveColIdx('name',         taxFields)   // Particulars / tax label
    int amountIdx  = resolveColIdx('amount',       taxFields)   // Amount column
    int typeUseIdx = resolveColIdx('type_tax_use', taxFields)   // explicit type_tax_use
    int activeIdx  = resolveColIdx('active',       taxFields)   // active flag

    // account_move fields — voucher context
    int vchNoIdx   = resolveColIdx('ref',         moveFields)   // Vch No.
    int dateIdx    = resolveColIdx('date',         moveFields)  // Date
    int vchTypeIdx = resolveColIdx('move_type',   moveFields)   // Vch Type
    int partyIdx   = resolveColIdx('partner_id',  moveFields)   // Party Name

    // Positional fallbacks — only when mappings yield no match
    if (vchNoIdx   < 0) { vchNoIdx   = 0; log.warn('[Step3A] vchNoIdx   fallback → col 0') }
    if (dateIdx    < 0) { dateIdx    = 1; log.warn('[Step3A] dateIdx    fallback → col 1') }
    if (vchTypeIdx < 0) { vchTypeIdx = 2; log.warn('[Step3A] vchTypeIdx fallback → col 2') }
    if (partyIdx   < 0) { partyIdx   = 3; log.warn('[Step3A] partyIdx   fallback → col 3') }
    if (partIdx    < 0) { partIdx    = 4; log.warn('[Step3A] partIdx    fallback → col 4') }
    if (amountIdx  < 0) { amountIdx  = 7; log.warn('[Step3A] amountIdx  fallback → col 7') }

    log.info("[Step3A] STEP6: FINAL col indices — vchNo:${vchNoIdx} date:${dateIdx} " +
             "vchType:${vchTypeIdx} party:${partyIdx} part:${partIdx} " +
             "amount:${amountIdx} typeUse:${typeUseIdx} active:${activeIdx}")

    if (partIdx < 0) {
        log.error('[Step3A] Cannot find Particulars column — check source_col/source_cols ' +
                  'for "name" field under account_tax in mappings.json')
        session.transfer(flowFile, REL_FAILURE); return
    }

    // ── 7. Scan rows — build 01_tax_lines.csv ────────────────────────────────
    // 'name'   = tax name  → LoadTaxGroup + LoadTax both read row['name']
    // 'amount' = tax rate  → LoadTax reads row['amount']
    def TAX_LINES_COLS = [
        'id', 'vch_no', 'vch_date', 'party_name', 'vch_type',
        'name',          // ← tax name  (LoadTaxGroup/LoadTax compatible)
        'amount',        // ← tax rate % (LoadTax compatible)
        'tax_amount',    // ← rupee amount from voucher
        'type_tax_use', 'amount_type', 'tax_group_name', 'active'
    ]

    def sbLines     = new StringBuilder()
    sbLines.append(TAX_LINES_COLS.join(',')).append('\n')

    String curVchNo   = ''
    String curVchDate = ''
    String curParty   = ''
    String curVchType = ''
    int    linesWritten = 0

    for (int i = headerLineIdx + 1; i < lines.size(); i++) {
        def cells = TallyCleaners_Taxes.splitCsvLine(lines[i])

        if (TallyCleaners_Taxes.isSkipRow(cells))    continue
        if (TallyCleaners_Taxes.isGrandTotal(cells)) continue

        // Voucher header row — Vch No. cell non-empty
        def vchNo = TallyCleaners_Taxes.cell(cells, vchNoIdx)
        if (vchNo) {
            curVchNo   = vchNo
            curVchDate = TallyCleaners_Taxes.cell(cells, dateIdx)
            curParty   = TallyCleaners_Taxes.cell(cells, partyIdx)
            curVchType = TallyCleaners_Taxes.cell(cells, vchTypeIdx)
            log.info("[Step3A] Header row ${i}: vchNo='${curVchNo}' type='${curVchType}' party='${curParty}'")
            continue
        }

        // Detail row — check if it is a tax row
        def label = TallyCleaners_Taxes.cell(cells, partIdx)
        if (!label) continue

        log.info("[Step3A] DEBUG row ${i}: label='${label}' isTax=${TallyCleaners_Taxes.isTaxRow(label, taxKeywords, roundingKeywords)}")

        if (!TallyCleaners_Taxes.isTaxRow(label, taxKeywords, roundingKeywords)) continue

        def taxName      = TallyCleaners_Taxes.cleanTaxName(label)
        def taxRate      = TallyCleaners_Taxes.parseRate(taxName)
        def taxAmtRaw    = TallyCleaners_Taxes.cell(cells, amountIdx)
        def explicitType = TallyCleaners_Taxes.cell(cells, typeUseIdx)
        def activeRaw    = TallyCleaners_Taxes.cell(cells, activeIdx)

        def typeUse  = TallyCleaners_Taxes.deriveTypeUse(taxName, explicitType, curVchType, purchaseTypeKw, purchaseTaxGrpK)
        def taxGroup = TallyCleaners_Taxes.deriveTaxGroup(taxName, taxGroupPatterns)
        def active   = TallyCleaners_Taxes.deriveActive(activeRaw)

        def lineId = "taxline_${curVchNo.replaceAll(/[^A-Za-z0-9]/, '_')}_${taxName.replaceAll(/[^A-Za-z0-9]/, '_')}"

        def lineRow = [
            lineId,
            curVchNo,
            curVchDate,
            curParty,
            curVchType,
            taxName,                                                          // → 'name'
            taxRate != null ? String.format('%.1f', taxRate) : '',            // → 'amount' (rate %)
            TallyCleaners_Taxes.fmtAmount(taxAmtRaw),                        // → 'tax_amount' (₹)
            typeUse,
            'percent',
            taxGroup,
            active
        ]

        sbLines.append(lineRow.collect { TallyCleaners_Taxes.escapeCsv(it?.toString() ?: '') }.join(',')).append('\n')
        linesWritten++
    }

    log.info("[Step3A] STEP7: ${linesWritten} tax lines written")

    if (linesWritten == 0) {
        log.warn('[Step3A] No tax rows detected — verify line_type_patterns.tax_keywords ' +
                 'in mappings.json matches your Tally tax line labels')
        session.transfer(flowFile, REL_FAILURE); return
    }

    // ── 8. Write single flowfile ──────────────────────────────────────────────
    def outBytes = sbLines.toString().getBytes(StandardCharsets.UTF_8)
    flowFile = session.write(flowFile, { _, out -> out.write(outBytes) } as StreamCallback)
    flowFile = session.putAllAttributes(flowFile, [
        'mime.type'  : 'text/csv',
        'filename'   : '01_tax_lines.csv',
        'entity.type': 'tax_lines',
        'row.count'  : linesWritten.toString()
    ])

    log.info("[Step3A] Done — 01_tax_lines.csv: ${linesWritten} rows")
    session.transfer(flowFile, REL_SUCCESS)

} catch (Exception e) {
    log.error("[Step3A] Failed: ${e.message}", e)
    session.transfer(flowFile, REL_FAILURE)
}

import groovy.json.JsonSlurper
import org.apache.commons.io.IOUtils
import java.nio.charset.StandardCharsets

def ff = session.get()
if (!ff) return

def ser   = { v, o -> o.write(v.toString().getBytes('UTF-8')) } as org.apache.nifi.distributed.cache.client.Serializer
def deser = { b -> new String(b, 'UTF-8') }                     as org.apache.nifi.distributed.cache.client.Deserializer

def safeLong = { def v ->
    if (v == null) return null
    def s = v?.toString()?.trim()
    if (!s || s == 'null' || s == 'CLEARED') return null
    try { return s.toLong() } catch (ignored) { return null }
}

def safeBigDecimal = { def v ->
    if (v == null) return BigDecimal.ZERO
    def s = v.toString().trim().replaceAll('[^0-9.\\-]', '')
    if (!s || s == '.' || s == '-') return BigDecimal.ZERO
    try { return s.toBigDecimal() } catch (ignored) { return BigDecimal.ZERO }
}

def nvl = { def v ->
    def s = v?.toString()?.trim()
    (s && s != 'null') ? s : null
}

try {
    // ── 1. Read JSON row ──────────────────────────────────────────────────────
    def jsonText = ''
    session.read(ff, { is ->
        jsonText = IOUtils.toString(is, StandardCharsets.UTF_8)
    } as org.apache.nifi.processor.io.InputStreamCallback)

    def row = new JsonSlurper().parseText(jsonText)
    log.info('LoadTax row: ' + row.toString()?.take(300))

    // ── 2. Read row fields — keys are already Odoo staging column names ───────
    def taxName  = nvl(row['name'])
    def typeUse  = nvl(row['type_tax_use'])  ?: 'sale'
    def amtType  = nvl(row['amount_type'])   ?: 'percent'
    def amount   = safeBigDecimal(row['amount'])
    def activeStr = nvl(row['active'])       ?: 'True'
    def active   = !(activeStr.toLowerCase() in ['false', '0', 'no', 'n'])
    def groupName = nvl(row['tax_group_name'])

    if (!taxName || taxName == 'name') {
        log.warn('Header or empty row — skipping')
        session.transfer(ff, REL_SUCCESS)
        return
    }

    log.info("taxName=${taxName} typeUse=${typeUse} amount=${amount} groupName=${groupName}")

    // ── 3. Runtime constants — cache / env only ───────────────────────────────
    def cacheGet = { String key ->
        try {
            def v = CTL.cacheClient.get(key, ser, deser)
            return (v && v != 'CLEARED') ? v.trim() : null
        } catch (ignored) { return null }
    }

    def compId   = safeLong(cacheGet('lookup.company_id')) ?: 1L
    def ctryId   = safeLong(cacheGet('lookup.country_id_in') ?: cacheGet('lookup.country_id'))
    def adminUid = (System.getenv('PG_ADMIN_UID') ?: '1').toLong()
    def module   = System.getenv('MIGRATION_MODULE') ?: '__migration__'

    if (!ctryId) throw new Exception('country_id not in cache — re-run Bootstrap')

// ── 4. Resolve tax_group_id — 4-tier fallback ─────────────────────────────

    // Tier 1: FlowFile attribute passed from insert_tax_group.groovy upstream
    def taxGroupIdStr = ff.getAttribute('tax_group_id')
    log.info("tax_group_id from FF attr: [${taxGroupIdStr}]")

    // Tier 2: Cache lookup by groupName from row data
    if (!taxGroupIdStr?.trim() || taxGroupIdStr == 'CLEARED') {
        if (groupName) {
            def groupSlug = groupName.toLowerCase().replaceAll(/[^a-z0-9]/, '_')
            taxGroupIdStr = cacheGet('taxgroup.' + groupSlug)
            log.info("tax_group_id from cache key [taxgroup.${groupSlug}] = [${taxGroupIdStr}]")
        }
    }

    // Tier 3: Cache lookup derived from the tax name itself
    // (handles case where tax_group_name column is missing in the CSV row)
    if (!taxGroupIdStr?.trim() || taxGroupIdStr == 'CLEARED') {
        // Derive group from tax name: CGST/SGST/IGST → gst, TDS → tds, TCS → tcs
        def derivedGroup = ''
        def tl = taxName?.toLowerCase() ?: ''
        if      (tl.contains('igst'))             derivedGroup = 'gst'
        else if (tl.contains('cgst'))             derivedGroup = 'gst'
        else if (tl.contains('sgst'))             derivedGroup = 'gst'
        else if (tl.contains('utgst'))            derivedGroup = 'gst'
        else if (tl.contains('gst'))              derivedGroup = 'gst'
        else if (tl.contains('tds'))              derivedGroup = 'tds'
        else if (tl.contains('tcs'))              derivedGroup = 'tcs'
        else                                      derivedGroup = 'other_taxes'

        taxGroupIdStr = cacheGet('taxgroup.' + derivedGroup)
        log.info("tax_group_id from derived group [taxgroup.${derivedGroup}] = [${taxGroupIdStr}]")
    }

    // Tier 4: Direct DB lookup on account_tax_group by name (JSONB column)
    if (!taxGroupIdStr?.trim() || taxGroupIdStr == 'CLEARED') {
        def searchName = groupName ?: taxName ?: ''
        if (searchName) {
            SQL.myPool.eachRow(
                "SELECT id FROM account_tax_group WHERE name->>'en_US' ILIKE ? AND company_id=? LIMIT 1",
                ['%' + searchName + '%', compId]
            ) { r ->
                taxGroupIdStr = r.getLong('id').toString()
                log.info("tax_group_id from DB name search [${searchName}] = [${taxGroupIdStr}]")
            }
        }
    }

    // Tier 5: Any tax group for this company — absolute last resort, never fail
    if (!taxGroupIdStr?.trim() || taxGroupIdStr == 'CLEARED') {
        SQL.myPool.eachRow(
            'SELECT id FROM account_tax_group WHERE company_id=? ORDER BY sequence, id LIMIT 1',
            [compId]
        ) { r ->
            taxGroupIdStr = r.getLong('id').toString()
            log.warn("tax_group_id last-resort fallback = [${taxGroupIdStr}] for tax '${taxName}'")
        }
    }

    def taxGroupId = safeLong(taxGroupIdStr)
    if (!taxGroupId) {
        log.error("MISSING tax_group_id for: ${taxName} — no account_tax_group exists for company ${compId}")
        ff = session.putAttribute(ff, 'error', "missing tax_group_id for ${taxName}")
        session.transfer(ff, REL_FAILURE)
        return
    }

    log.info("taxGroupId resolved = ${taxGroupId}")

    // ── 5. Build ext_id ───────────────────────────────────────────────────────
    def taxSlug = taxName.replaceAll(/%/, '').replaceAll(/[^A-Za-z0-9]+/, '_')
                         .toUpperCase().replaceAll(/^_|_$/, '')
    def extId   = 'tally_tax_' + taxSlug + '_' + typeUse.toUpperCase()

    // ── 6. Cache check ────────────────────────────────────────────────────────
    def cacheKey   = 'tax.' + taxName + '_' + typeUse
    def cachedTaxId = cacheGet(cacheKey)
    if (cachedTaxId) {
        log.info("Tax already cached: ${taxName} → ${cachedTaxId}")
        ff = session.putAttribute(ff, 'tax_id',   cachedTaxId)
        ff = session.putAttribute(ff, 'tax_name', taxName)
        session.transfer(ff, REL_SUCCESS)
        return
    }

    // ── 7. DB check ───────────────────────────────────────────────────────────
    def existingTaxId = null
    SQL.myPool.eachRow(
        'SELECT res_id FROM ir_model_data WHERE module=? AND name=?',
        [module, extId]
    ) { r -> existingTaxId = r.getLong('res_id') }

    if (existingTaxId) {
        CTL.cacheClient.put(cacheKey, existingTaxId.toString(), ser, ser)
        log.info("Tax already in DB: ${taxName} → ${existingTaxId}")
        ff = session.putAttribute(ff, 'tax_id',   existingTaxId.toString())
        ff = session.putAttribute(ff, 'tax_name', taxName)
        session.transfer(ff, REL_SUCCESS)
        return
    }

    // ── 8. Build JSONB name ───────────────────────────────────────────────────
    def nameSafe = taxName.replace('"', '\\"')
    def nameJson = "{\"en_US\": \"${nameSafe}\"}"

    // ── 9. INSERT account_tax ─────────────────────────────────────────────────
    def ps = SQL.myPool.connection.prepareStatement(
        '''INSERT INTO account_tax
           (name, company_id, tax_group_id, country_id,
            sequence, amount, amount_type, type_tax_use,
            tax_exigibility, active,
            include_base_amount, is_base_affected, analytic, is_domestic,
            create_uid, write_uid, create_date, write_date)
           VALUES
           (?::jsonb, ?, ?, ?,
            10, ?, ?, ?,
            'on_invoice', ?,
            false, true, false, true,
            ?, ?, NOW(), NOW())
           RETURNING id'''
    )

    ps.setString(1,  nameJson)
    ps.setLong(2,    compId)
    ps.setLong(3,    taxGroupId)
    ps.setLong(4,    ctryId)
    ps.setBigDecimal(5, amount)
    ps.setString(6,  amtType)
    ps.setString(7,  typeUse)
    ps.setBoolean(8, active)
    ps.setLong(9,    adminUid)
    ps.setLong(10,   adminUid)

    def rs = ps.executeQuery()
    rs.next()
    def taxId = rs.getLong(1)
    ps.close()

    log.info("Tax INSERTED: ${taxName} → ${taxId}")

    // ── 10. Register XID ──────────────────────────────────────────────────────
    SQL.myPool.execute(
        '''INSERT INTO ir_model_data (module, name, model, res_id, noupdate, create_date, write_date)
           VALUES (?,?,?,?,false,NOW(),NOW()) ON CONFLICT (module,name) DO NOTHING''',
        [module, extId, 'account.tax', taxId]
    )

    // ── 11. INSERT 4 repartition lines ────────────────────────────────────────
    def ps2 = SQL.myPool.connection.prepareStatement(
        '''INSERT INTO account_tax_repartition_line
           (tax_id, company_id, document_type, repartition_type,
            factor_percent, use_in_tax_closing, sequence,
            create_uid, write_uid, create_date, write_date)
           VALUES (?, ?, ?, ?, 100.0, ?, ?, ?, ?, NOW(), NOW())
           ON CONFLICT DO NOTHING'''
    )

    [
        ['invoice', 'base', false, 1],
        ['invoice', 'tax',  true,  2],
        ['refund',  'base', false, 1],
        ['refund',  'tax',  true,  2],
    ].each { docType, reptType, useInClosing, seq ->
        ps2.setLong(1,    taxId)
        ps2.setLong(2,    compId)
        ps2.setString(3,  docType)
        ps2.setString(4,  reptType)
        ps2.setBoolean(5, useInClosing)
        ps2.setInt(6,     seq)
        ps2.setLong(7,    adminUid)
        ps2.setLong(8,    adminUid)
        ps2.addBatch()
    }
    ps2.executeBatch()
    ps2.close()

    log.info("4 repartition lines INSERTED for: ${taxName}")

    CTL.cacheClient.put(cacheKey,           taxId.toString(), ser, ser)
    CTL.cacheClient.put('tax.' + taxName,   taxId.toString(), ser, ser)

    ff = session.putAttribute(ff, 'tax_id',   taxId.toString())
    ff = session.putAttribute(ff, 'tax_name', taxName)
    session.transfer(ff, REL_SUCCESS)

} catch (Exception e) {
    log.error('LoadTax failed: ' + e.message, e)
    ff = session.putAttribute(ff, 'error',       e.message)
    ff = session.putAttribute(ff, 'error.cause', e.getCause()?.getMessage() ?: 'none')
    session.transfer(ff, REL_FAILURE)
}

import groovy.json.JsonOutput

// ── Serializer / Deserializer ─────────────────────────────────────────────
def ser   = { v, o -> o.write(v.bytes) } as org.apache.nifi.distributed.cache.client.Serializer
def deser = { b -> new String(b) }       as org.apache.nifi.distributed.cache.client.Deserializer

// ── Cache client via CTL. prefix ──────────────────────────────────────────
def cache = CTL.cacheClient

try {

    // ── company_id ────────────────────────────────────────────────────────
    def compId
    SQL.myPool.eachRow("SELECT id FROM res_company WHERE id = 1") { row ->
        compId = row.getLong(1)
    }
    cache.put('lookup.company_id', compId.toString(), ser, ser)
    log.info("Cached company_id: ${compId}")

    // ── currency_id (INR) ─────────────────────────────────────────────────
    def currencyId
    SQL.myPool.eachRow("SELECT id FROM res_currency WHERE name = 'INR'") { row ->
        currencyId = row.getLong(1)
    }
    cache.put('lookup.currency_id', currencyId.toString(), ser, ser)
    cache.put('lookup.currency_id_inr', currencyId.toString(), ser, ser)
    log.info("Cached currency_id: ${currencyId}")

    // ── country_id (India) ────────────────────────────────────────────────
    def ctryId
    SQL.myPool.eachRow("SELECT id FROM res_country WHERE code = 'IN'") { row ->
        ctryId = row.getLong(1)
    }
    cache.put('lookup.country_id', ctryId.toString(), ser, ser)
    cache.put('lookup.country_id_in', ctryId.toString(), ser, ser)
    log.info("Cached country_id: ${ctryId}")

    // ── Detect name column type helper ────────────────────────────────────
    def getNameColType = { tableName ->
        def colType = ''
        SQL.myPool.eachRow("""
            SELECT data_type FROM information_schema.columns
            WHERE table_name = '${tableName}' AND column_name = 'name'
        """) { row -> colType = row.getString(1) }
        return colType
    }

    // ── states ────────────────────────────────────────────────────────────
    def states = [:]
    def stateQuery = getNameColType('res_country_state') == 'jsonb'
        ? "SELECT name->>'en_US' AS state_name, id FROM res_country_state WHERE country_id = ${ctryId}"
        : "SELECT name AS state_name, id FROM res_country_state WHERE country_id = ${ctryId}"

    SQL.myPool.eachRow(stateQuery) { row ->
        def stateName = row.getString('state_name')
        if (stateName) {
            states[stateName] = row.getLong('id')
            cache.put("lookup.state.${stateName}", row.getLong('id').toString(), ser, ser)
        }
    }
    log.info("Cached all states: ${states.size()} entries")

    // ── uoms ──────────────────────────────────────────────────────────────
    def uoms = [:]
    def uomQuery = getNameColType('uom_uom') == 'jsonb'
        ? "SELECT name->>'en_US' AS uom_name, id FROM uom_uom WHERE active = true"
        : "SELECT name AS uom_name, id FROM uom_uom WHERE active = true"

    SQL.myPool.eachRow(uomQuery) { row ->
        def uomName = row.getString('uom_name')
        if (uomName) {
            uoms[uomName] = row.getLong('id')
            cache.put("lookup.uom.${uomName}", row.getLong('id').toString(), ser, ser)
        }
    }
    log.info("Cached all UOMs: ${uoms.size()} entries")

    // ── journals ──────────────────────────────────────────────────────────
    def journals = [:]
    def journalQuery = getNameColType('account_journal') == 'jsonb'
        ? "SELECT name->>'en_US' AS journal_name, id FROM account_journal WHERE company_id = ${compId}"
        : "SELECT name AS journal_name, id FROM account_journal WHERE company_id = ${compId}"

    SQL.myPool.eachRow(journalQuery) { row ->
        def journalName = row.getString('journal_name')
        if (journalName) {
            journals[journalName] = row.getLong('id')
            cache.put("lookup.journal.${journalName}", row.getLong('id').toString(), ser, ser)
        }
    }
    log.info("Cached all journals: ${journals.size()} entries")

    // ── Build JSON payload ────────────────────────────────────────────────
    def payload = [
        company_id  : compId,
        currency_id : currencyId,
        country_id  : ctryId,
        states      : states,
        uoms        : uoms,
        journals    : journals
    ]

    def jsonOutput = JsonOutput.prettyPrint(JsonOutput.toJson(payload))
    log.info("Bootstrap complete: all lookup IDs cached successfully")

    // ── Write JSON into FlowFile and transfer to SUCCESS ──────────────────
    def ff = session.get() ?: session.create()
    ff = session.write(ff, { outputStream ->
        outputStream.write(jsonOutput.getBytes('UTF-8'))
    } as org.apache.nifi.processor.io.OutputStreamCallback)

    session.putAttribute(ff, 'mime.type', 'application/json')
    session.putAttribute(ff, 'filename', 'bootstrap_lookup.json')
    session.transfer(ff, REL_SUCCESS)

} catch (Exception e) {
    log.error("Bootstrap error: ${e.message}", e)
    def ff = session.get() ?: session.create()
    session.transfer(ff, REL_FAILURE)
}

import groovy.json.JsonSlurper
import groovy.json.JsonOutput

// ── Serializer / Deserializer ─────────────────────────────────────────────
def ser   = { v, o -> o.write(v.bytes) } as org.apache.nifi.distributed.cache.client.Serializer
def deser = { b -> new String(b) }       as org.apache.nifi.distributed.cache.client.Deserializer

// ── Cache client via CTL. prefix ──────────────────────────────────────────
def cache = CTL.cacheClient

try {
    // ── Read JSON from flowfile ───────────────────────────────────────────
    def ff = session.get() ?: session.create()
    def body = ''
    session.read(ff, { inputStream ->
        body = inputStream.text
    } as org.apache.nifi.processor.io.InputStreamCallback)

    if (!body?.trim()) throw new Exception("Flowfile is empty — check GenerateFlowFile Custom Text")

    def config = new JsonSlurper().parseText(body)

    // ── Store full config in cache ────────────────────────────────────────
    cache.put('tally.mapping.config', body, ser, ser)
    log.info("Stored full mapping config in cache")

    // ── Store per-table slices ────────────────────────────────────────────
    def tableCount = 0
    config.tables?.each { tableId, tableCfg ->
        cache.put(
            "tally.mapping.table.${tableId}",
            JsonOutput.toJson(tableCfg),
            ser, ser
        )
        log.info("Cached mapping for table: ${tableId}")
        tableCount++
    }

    // ── Store transform glossary ──────────────────────────────────────────
    if (config.transform_glossary) {
        cache.put(
            'tally.mapping.glossary',
            JsonOutput.toJson(config.transform_glossary),
            ser, ser
        )
        log.info("Cached transform glossary: ${config.transform_glossary.size()} entries")
    }

    // ── Store pipeline info ───────────────────────────────────────────────
    if (config.pipeline_info) {
        cache.put(
            'tally.mapping.pipeline_info',
            JsonOutput.toJson(config.pipeline_info),
            ser, ser
        )
        log.info("Cached pipeline info")
    }

    config.tables?.each { 
		tableId, tableCfg ->
        log.info("Cached mapping config: ${tableCfg}")
        cache.put("tally.mapping.table.${tableId}", JsonOutput.toJson(tableCfg), ser, ser)
        log.info("Cached mapping for: ${tableId}")
    }

    log.info("Mapping explode complete — ${tableCount} tables cached")

    ff = session.putAttribute(ff, 'mapping.tables.count', tableCount.toString())
    ff = session.putAttribute(ff, 'mapping.status', 'exploded')
    session.transfer(ff, REL_SUCCESS)

} catch (Exception e) {
    log.error("Mapping explode error: ${e.message}", e)
    def ff = session.get() ?: session.create()
    ff = session.putAttribute(ff, 'mapping.error', e.message)
    session.transfer(ff, REL_FAILURE)
}

import TallyCleaner
import org.apache.nifi.processor.io.InputStreamCallback
import groovy.json.JsonSlurper
import java.nio.charset.StandardCharsets

def flowFile = session.get()
if (!flowFile) return

try {
    // ── 1. Load mappings ──────────────────────────────────────────────────────
    def mappingsPath = flowFile.getAttribute('mappings.path') ?: '/home/ubuntu/Raw_tally_data/mappings.json'
    log.info("[CoA] STEP1: Loading mappings from: ${mappingsPath}")

    def mappingJson = new File(mappingsPath).text
    def mappings    = new JsonSlurper().parseText(mappingJson)

    // tally_group_to_odoo — already at root of mappings.json
    def groupMap  = mappings.tally_group_to_odoo ?: [:]

    // account_account table config — already in mappings.tables.account_account
    def coaTable  = mappings.tables?.account_account ?: [:]
    def coaFields = coaTable.fields ?: [:]

    log.info("[CoA] STEP1: coaFields loaded — ${coaFields.size()} fields")

    if (coaFields.isEmpty()) {
        log.error("[CoA] STEP1: tables.account_account.fields is EMPTY — check mappings.json")
        session.transfer(flowFile, REL_FAILURE)
        return
    }
    if (groupMap.isEmpty()) {
        log.error("[CoA] STEP1: tally_group_to_odoo is EMPTY — check mappings.json")
        session.transfer(flowFile, REL_FAILURE)
        return
    }

    // ── 2. Read CSV ───────────────────────────────────────────────────────────
    String csvText = ''
    session.read(flowFile, { is -> csvText = is.text } as InputStreamCallback)

    def lines = csvText.readLines().findAll { it.trim() }
    log.info("[CoA] STEP2: Total lines: ${lines.size()}")

    if (lines.size() < 2) {
        log.warn('[CoA] STEP2: Empty file — skipping')
        session.transfer(flowFile, REL_FAILURE)
        return
    }

    def headers = TallyCleaners.splitCsvLine(lines[0])
    log.info("[CoA] STEP2: CSV headers: ${headers}")

    // ── 3. Build header index — skip empty headers (identical to contacts) ────
    def headerIdx = [:]
    headers.eachWithIndex { h, i ->
        def key = h?.trim()?.toLowerCase() ?: ''
        if (key) headerIdx[key] = i
    }
    log.info("[CoA] STEP3: headerIdx: ${headerIdx}")

    // ── 4. Alias-driven column resolver — exact copy of contacts pattern ──────
    def resolveColIdx = { String odooField ->
        def fm = coaFields[odooField]
        if (!fm) {
            log.warn("[CoA] STEP4: '${odooField}' not in coaFields")
            return -1
        }

        def candidates = []
        if (fm.source_col)                              candidates << fm.source_col.toString().trim()
        if (fm.source_cols instanceof List) candidates += fm.source_cols*.toString()*.trim()
        candidates = candidates.findAll { it }

        // a) Exact match first
        for (String alias in candidates) {
            def aliasL = alias.toLowerCase()
            if (headerIdx.containsKey(aliasL)) {
                log.info("[CoA] STEP4: '${odooField}' → EXACT '${alias}' → col ${headerIdx[aliasL]}")
                return headerIdx[aliasL]
            }
        }

        // b) Contains fallback
        for (String alias in candidates) {
            def aliasL = alias.toLowerCase()
            if (!aliasL) continue
            def found = headerIdx.find { k, v ->
                k && k.trim() && (k.contains(aliasL) || aliasL.contains(k))
            }
            if (found) {
                log.info("[CoA] STEP4: '${odooField}' → CONTAINS '${alias}' ~ '${found.key}' → col ${found.value}")
                return found.value
            }
        }

        log.warn("[CoA] STEP4: '${odooField}' → NO MATCH in headers")
        return -1
    }

    // ── 5. Resolve column indices ─────────────────────────────────────────────
    // Field names match exactly what is in mappings.tables.account_account.fields
    int nameIdx    = resolveColIdx('name')        
    int groupIdx   = resolveColIdx('tally_group') 
    int codeIdx    = resolveColIdx('code_store')  

    log.info("[CoA] STEP5: FINAL indices — name:${nameIdx} group:${groupIdx} code:${codeIdx}")

    if (nameIdx < 0) {
        log.error("[CoA] STEP5: nameIdx=-1 — name column not found — all rows will be skipped")
        session.transfer(flowFile, REL_FAILURE)
        return
    }
    if (groupIdx < 0) {
        log.error("[CoA] STEP5: groupIdx=-1 — tally_group/under column not found — cannot map account types")
        session.transfer(flowFile, REL_FAILURE)
        return
    }

    // ── 6. Output config — all from mappings, ──────────────
    // output_cols, id_prefix, filename — add these 3 keys to account_account in mappings.json
    // (see mappings_coa_additions.json); fallback defaults keep script working without them
    def OUT_COLS    = (coaTable.output_cols   as List<String>) ?: ['id', 'code_store', 'name', 'account_type', 'reconcile']
    def idPrefix    = coaTable.id_prefix   ?: 'tally_account_'
    def outFilename = coaTable.filename    ?: '02_coa.csv'

    // Code counter — auto-generates prefix001, prefix002 … per prefix group
    def codeCounters = [:]
    def nextCode = { String prefix ->
        def n = (codeCounters[prefix] ?: 0) + 1
        codeCounters[prefix] = n
        return prefix + String.format('%03d', n)
    }

    def sb      = new StringBuilder().append(OUT_COLS.join(',')).append('\n')
    int written = 0
    int skipped = 0

    // ── 7. Process rows ───────────────────────────────────────────────────────
    for (int i = 1; i < lines.size(); i++) {
        def rawCells = TallyCleaners.splitCsvLine(lines[i])
        def cells    = TallyCleaners.fixShiftedRow(rawCells, headers, nameIdx)

        // a) Name — mandatory
        def name = TallyCleaners.cell(cells, nameIdx)
        if (!name || TallyCleaners.isEmpty(name)) {
            skipped++
            continue
        }

        // b) Tally group → Odoo entry
        def tallyGroup = TallyCleaners.cell(cells, groupIdx)?.trim()
        def entry      = groupMap[tallyGroup]
        if (!entry) {
            log.warn("[CoA] STEP7: Unknown group '${tallyGroup}' for '${name}' — skipping")
            skipped++
            continue
        }

        // c) Account code — use CSV column if present (code_store/alias), else auto-generate
        def code
        if (codeIdx >= 0) {
            def csvCode = TallyCleaners.cell(cells, codeIdx)?.trim()
            code = (csvCode && !TallyCleaners.isEmpty(csvCode)) ? csvCode : nextCode(entry.code_prefix as String)
        } else {
            code = nextCode(entry.code_prefix as String)
        }

        // d) Assemble row — OUT_COLS drives order and which fields appear
        def vals = [
            'id'          : idPrefix + code,
            'code_store'        : code,
            'name'        : name,
            'account_type': entry.account_type as String,
            'reconcile'   : entry.reconcile ? 'True' : 'False',
            'tally_group' : tallyGroup ?: '',
        ]

        def row = OUT_COLS.collect { vals.getOrDefault(it, '') }
        sb.append(row.collect { TallyCleaners.escapeCsv(it as String) }.join(',')).append('\n')
        log.info("[CoA] [row] ${row}")
        written++
    }

    log.info("[CoA] STEP7: DONE — written=${written} skipped=${skipped} of ${lines.size() - 1} rows")

    if (written == 0) {
        log.warn('[CoA] STEP7: No valid rows produced — check tally_group_to_odoo coverage in mappings.json')
        session.transfer(flowFile, REL_FAILURE)
        return
    }

    // ── 8. Write output ───────────────────────────────────────────────────────
    flowFile = session.write(flowFile, { inStream, outStream ->
        outStream.write(sb.toString().getBytes(StandardCharsets.UTF_8))
    } as org.apache.nifi.processor.io.StreamCallback)

    session.putAttribute(flowFile, 'mime.type',    'text/csv')
    session.putAttribute(flowFile, 'filename',     outFilename)
    session.putAttribute(flowFile, 'staging.file', outFilename)
    session.putAttribute(flowFile, 'entity.type',  'coa')
    session.putAttribute(flowFile, 'row.count',    written.toString())
    log.info("[CoA] STEP8: Complete — ${outFilename} — row.count=${written}")
    session.transfer(flowFile, REL_SUCCESS)

} catch (Exception e) {
    log.error('[CoA] FAILED: ' + e.message, e)
    session.transfer(flowFile, REL_FAILURE)
}

import groovy.json.JsonOutput
import groovy.json.JsonSlurper
import org.apache.commons.io.IOUtils
import java.nio.charset.StandardCharsets

def ff = session.get()
if (!ff) return

def ser   = { v, o -> o.write(v.toString().getBytes('UTF-8')) } as org.apache.nifi.distributed.cache.client.Serializer
def deser = { b -> new String(b, 'UTF-8') }                     as org.apache.nifi.distributed.cache.client.Deserializer

def safeLong = { def v ->
    if (v == null) return null
    def s = v?.toString()?.trim()
    if (!s || s == 'null' || s == 'CLEARED') return null
    try { return s.toLong() } catch (ignored) { return null }
}

def nvl = { def v ->
    def s = v?.toString()?.trim()
    (s && s != 'null') ? s : null
}

try {
    // ── 1. Read JSON row ──────────────────────────────────────────────────────
    def jsonText = ''
    session.read(ff, { is ->
        jsonText = IOUtils.toString(is, StandardCharsets.UTF_8)
    } as org.apache.nifi.processor.io.InputStreamCallback)

    def row = new JsonSlurper().parseText(jsonText)
    log.info('insert_account_account row: ' + row.toString()?.take(300))

    // ── 2. Read fields ────────────────────────────────────────────────────────
    def name        = nvl(row['name'])
    def accountType = nvl(row['account_type'])
    def reconcile   = row['reconcile']?.toString()?.trim()?.toLowerCase() == 'true'
    def csvCode     = nvl(row['code_store'])

    log.info("name=${name} accountType=${accountType} reconcile=${reconcile} csvCode=${csvCode}")

    if (!name) {
        log.warn('Empty name — skipping')
        session.transfer(ff, REL_SUCCESS)
        return
    }
    if (!accountType) {
        log.warn("Empty account_type for '${name}' — skipping")
        session.transfer(ff, REL_SUCCESS)
        return
    }

    // ── 3. Runtime constants ──────────────────────────────────────────────────
    def cacheGet = { String key ->
        try {
            def v = CTL.cacheClient.get(key, ser, deser)
            return (v && v != 'CLEARED') ? v.trim() : null
        } catch (ignored) { return null }
    }

    def compId   = safeLong(cacheGet('lookup.company_id')) ?: 1L
    def adminUid = (System.getenv('PG_ADMIN_UID') ?: '1').toLong()
    def module   = System.getenv('MIGRATION_MODULE') ?: '__migration__'

    // ── 4. Resolve account code ───────────────────────────────────────────────
    def code = csvCode

    if (!code) {
        def prefixMap = [
            asset_receivable    : '13',
            liability_payable   : '21',
            asset_cash          : '11',
            asset_fixed         : '16',
            asset_current       : '14',
            asset_non_current   : '15',
            equity              : '31',
            income              : '41',
            income_other        : '42',
            expense             : '51',
            expense_direct_cost : '52',
            liability_current   : '22',
            liability_non_current: '23',
            liability_credit_card: '22',
        ]
        def prefix      = prefixMap[accountType] ?: '90'
        def prefixFloor = "${prefix}000".toString()
        def compKey     = compId.toString()

        log.info("code missing — auto-generating with prefix='${prefix}'")

        SQL.myPool.eachRow("""
            SELECT COALESCE(
                MAX((code_store->>'${compKey}')::int), ${prefixFloor}::int
            ) + 1 AS next_code
            FROM account_account
            WHERE code_store->>'${compKey}' LIKE '${prefix}%'
        """) { r -> code = r.next_code?.toString() }

        log.info("Auto-generated code='${code}'")
    }

    if (!code) throw new Exception("code could not be resolved for '${name}' accountType='${accountType}'")

    // ── 5. Build JSONB values ─────────────────────────────────────────────────
    def nameSafe = name.replace('"', '\\"')
    def nameJson = "{\"en_US\": \"${nameSafe}\"}"
    def codeJson = JsonOutput.toJson([(compId.toString()): code])
    log.info("nameJson=${nameJson} codeJson=${codeJson}")

    // ── 6. External ID ────────────────────────────────────────────────────────
    def extId = nvl(row['id']) ?: ('tally_account_' + code.replaceAll(/[^a-zA-Z0-9]/, '_'))
    log.info("extId=${extId}")

    // ── 7. Cache check ────────────────────────────────────────────────────────
    def cacheKey = 'xid.account_account.' + extId
    def cachedId = cacheGet(cacheKey)

    if (cachedId) {
        log.info("Account already cached: ${name} -> ${cachedId}")
        ff = session.putAttribute(ff, 'res_id',       cachedId)
        ff = session.putAttribute(ff, 'account_xid',  extId)
        ff = session.putAttribute(ff, 'account_code', code)
        session.transfer(ff, REL_SUCCESS)
        return
    }

    // ── 8. DB check ───────────────────────────────────────────────────────────
    def existingId = null
    SQL.myPool.eachRow(
        'SELECT res_id FROM ir_model_data WHERE module=? AND name=?',
        [module, extId]
    ) { r -> existingId = r.getLong('res_id') }

    long resId

    if (existingId) {
        // ── Already in DB — ensure company rel exists (handles re-runs / backfill)
        resId = existingId
        log.info("Account already in DB: ${name} -> ${resId} — ensuring company rel exists")

        SQL.myPool.execute(
            '''INSERT INTO account_account_res_company_rel (account_account_id, res_company_id)
               VALUES (?, ?)
               ON CONFLICT DO NOTHING''',
            [resId, compId]
        )

    } else {
        // ── 9. INSERT account_account ─────────────────────────────────────────
        // NOTE: No company_id column in Odoo 17+.
        // Company is encoded in code_store JSONB key AND in the junction table (step 11).
        def ps = SQL.myPool.connection.prepareStatement('''
            INSERT INTO account_account
              (account_type, name, code_store, reconcile, active,
               create_asset, non_trade,
               create_uid, write_uid, create_date, write_date)
            VALUES (
              ?, ?::jsonb, ?::jsonb, ?, true,
              'no', false,
              ?, ?, NOW(), NOW()
            )
            RETURNING id
        ''')

        int p = 1
        ps.setString(p++, accountType)
        ps.setString(p++, nameJson)
        ps.setString(p++, codeJson)
        ps.setBoolean(p++, reconcile)
        ps.setLong(p++,   adminUid)
        ps.setLong(p++,   adminUid)

        def rs = ps.executeQuery()
        rs.next()
        resId = rs.getLong(1)
        ps.close()

        log.info("account_account INSERTED: ${name} (${code}) -> ${resId}")

        // ── 10. Register XID in ir_model_data ─────────────────────────────────
        SQL.myPool.execute(
            '''INSERT INTO ir_model_data
               (module, name, model, res_id, noupdate, create_date, write_date)
               VALUES (?,?,?,?,false,NOW(),NOW())
               ON CONFLICT (module,name) DO NOTHING''',
            [module, extId, 'account.account', resId]
        )

        SQL.myPool.execute(
            '''INSERT INTO account_account_res_company_rel (account_account_id, res_company_id)
               VALUES (?, ?)
               ON CONFLICT DO NOTHING''',
            [resId, compId]
        )

        log.info("Company rel inserted: account ${resId} -> company ${compId} — account now visible in UI")
    }

    // ── 12. Populate caches ───────────────────────────────────────────────────
    CTL.cacheClient.put(cacheKey,                        resId.toString(), ser, ser)
    CTL.cacheClient.put('account.code.' + code,          resId.toString(), ser, ser)
    CTL.cacheClient.put('account.name.' + name,          resId.toString(), ser, ser)
    CTL.cacheClient.put('xid.account_account.' + extId,  resId.toString(), ser, ser)

    ff = session.putAttribute(ff, 'res_id',       resId.toString())
    ff = session.putAttribute(ff, 'account_xid',  extId)
    ff = session.putAttribute(ff, 'account_code', code)
    session.transfer(ff, REL_SUCCESS)

} catch (Exception e) {
    log.error('insert_account_account failed: ' + e.message, e)
    ff = session.putAttribute(ff, 'error',       e.message)
    ff = session.putAttribute(ff, 'error.cause', e.getCause()?.getMessage() ?: 'none')
    session.transfer(ff, REL_FAILURE)
}
